   alt:["quaisquer dois cargos administrativos","dois cargos de professor; um de professor com outro técnico/científico; e dois cargos privativos de profissionais de saúde regulamentados","três cargos quaisquer","cargos em comissão ilimitados","apenas cargos no mesmo órgão"],
   cor:1,
